{
  "name": "Life Grid Visualizer",
  "description": "A poetic visualization of your life journey. Input your birth date to see exactly how many days you've spent on Earth and visualize your remaining 'months' in a 100-year life grid."
}

import React from 'react';
import ReactDOM from 'react-dom/client';
import App from './App';

const rootElement = document.getElementById('root');
if (!rootElement) {
  throw new Error("Could not find root element to mount to");
}

const root = ReactDOM.createRoot(rootElement);
root.render(
  <React.StrictMode>
    <App />
  </React.StrictMode>
);

import React, { useState, useMemo, useEffect } from 'react';
import { 
  Calendar, 
  Clock, 
  Hourglass, 
  Heart,
  ChevronRight,
  Info
} from 'lucide-react';
import { format, differenceInDays, differenceInMonths, addYears, isAfter, isBefore, startOfMonth } from 'date-fns';

const MAX_AGE_YEARS = 100;
const TOTAL_MONTHS = MAX_AGE_YEARS * 12;

const App: React.FC = () => {
  const [birthDate, setBirthDate] = useState<string>('');
  const [stats, setStats] = useState<{
    daysLived: number;
    monthsLived: number;
    percentLived: number;
    remainingDays: number;
  } | null>(null);

  const calculateStats = (date: string) => {
    if (!date) return;
    const birth = new Date(date);
    const now = new Date();
    const end = addYears(birth, MAX_AGE_YEARS);

    const days = differenceInDays(now, birth);
    const months = differenceInMonths(now, birth);
    const totalDaysPotential = differenceInDays(end, birth);
    const percent = Math.min((days / totalDaysPotential) * 100, 100);
    const remaining = Math.max(differenceInDays(end, now), 0);

    setStats({
      daysLived: Math.max(days, 0),
      monthsLived: Math.max(months, 0),
      percentLived: percent,
      remainingDays: remaining,
    });
  };

  useEffect(() => {
    if (birthDate) {
      calculateStats(birthDate);
    }
  }, [birthDate]);

  const gridItems = useMemo(() => {
    if (!birthDate) return [];
    const items = [];
    for (let i = 0; i < TOTAL_MONTHS; i++) {
      items.push(i < (stats?.monthsLived || 0));
    }
    return items;
  }, [stats?.monthsLived, birthDate]);

  return (
    <div className="min-h-screen pb-20 bg-gradient-to-br from-slate-50 to-blue-50">
      {/* Header */}
      <header className="bg-white border-b border-slate-200 sticky top-0 z-10 shadow-sm">
        <div className="max-w-5xl mx-auto px-4 py-4 flex flex-col sm:flex-row items-center justify-between gap-4">
          <div className="flex items-center gap-3">
            <div className="bg-indigo-600 p-2 rounded-xl text-white">
              <Hourglass size={24} />
            </div>
            <h1 className="text-xl font-bold text-slate-800 tracking-tight">Life Grid</h1>
          </div>

          <div className="flex items-center gap-4 w-full sm:w-auto">
            <div className="relative w-full">
              <Calendar className="absolute left-3 top-1/2 -translate-y-1/2 text-slate-400" size={18} />
              <input 
                type="date" 
                className="w-full sm:w-64 pl-10 pr-4 py-2 bg-slate-100 border-none rounded-lg focus:ring-2 focus:ring-indigo-500 outline-none transition-all"
                value={birthDate}
                onChange={(e) => setBirthDate(e.target.value)}
              />
            </div>
          </div>
        </div>
      </header>

      <main className="max-w-5xl mx-auto px-4 pt-8">
        {!birthDate ? (
          <div className="flex flex-col items-center justify-center py-20 text-center animate-in fade-in slide-in-from-bottom-4 duration-700">
            <div className="bg-white p-8 rounded-3xl shadow-xl border border-slate-100 max-w-md">
              <div className="bg-indigo-50 w-16 h-16 rounded-2xl flex items-center justify-center mx-auto mb-6 text-indigo-600">
                <Clock size={32} />
              </div>
              <h2 className="text-2xl font-bold mb-4 text-slate-800">When did your journey begin?</h2>
              <p className="text-slate-500 mb-8">Enter your birthday to visualize your life in months and see how many days you've been exploring this world.</p>
              <div className="text-xs text-slate-400 flex items-center justify-center gap-2">
                <Info size={14} />
                <span>We calculate based on a 100-year perspective</span>
              </div>
            </div>
          </div>
        ) : (
          <div className="space-y-8 animate-in fade-in duration-500">
            {/* Stats Dashboard */}
            <div className="grid grid-cols-1 md:grid-cols-3 gap-6">
              <StatCard 
                title="Days Spent" 
                value={stats?.daysLived.toLocaleString()} 
                subtitle="Nights & Mornings"
                icon={<Clock className="text-indigo-500" />}
                color="bg-indigo-50"
              />
              <StatCard 
                title="Life Progress" 
                value={`${stats?.percentLived.toFixed(1)}%`} 
                subtitle={`Of ${MAX_AGE_YEARS} Years`}
                icon={<Heart className="text-rose-500" />}
                color="bg-rose-50"
              />
              <StatCard 
                title="Days Ahead" 
                value={stats?.remainingDays.toLocaleString()} 
                subtitle="Approx. Potential"
                icon={<ChevronRight className="text-emerald-500" />}
                color="bg-emerald-50"
              />
            </div>

            {/* The Grid */}
            <div className="bg-white p-6 sm:p-10 rounded-3xl shadow-xl border border-slate-100">
              <div className="flex flex-col sm:flex-row items-start sm:items-center justify-between mb-8 gap-4">
                <div>
                  <h3 className="text-xl font-bold text-slate-800">Your 1,200 Months</h3>
                  <p className="text-slate-500">Each square represents one month of your life.</p>
                </div>
                <div className="flex gap-4 text-sm font-medium">
                  <div className="flex items-center gap-2">
                    <div className="w-4 h-4 rounded-sm bg-indigo-600 shadow-sm shadow-indigo-200"></div>
                    <span className="text-slate-600">Past</span>
                  </div>
                  <div className="flex items-center gap-2">
                    <div className="w-4 h-4 rounded-sm bg-slate-100 border border-slate-200"></div>
                    <span className="text-slate-600">Future</span>
                  </div>
                </div>
              </div>

              {/* Grid Container */}
              <div className="grid grid-cols-12 sm:grid-cols-24 md:grid-cols-30 lg:grid-cols-40 gap-1.5 md:gap-2">
                {gridItems.map((lived, idx) => (
                  <div 
                    key={idx}
                    className={`
                      aspect-square rounded-[2px] md:rounded-sm transition-all duration-300
                      ${lived 
                        ? 'bg-indigo-600 shadow-sm shadow-indigo-200 scale-100' 
                        : 'bg-slate-50 border border-slate-200 hover:border-indigo-300'
                      }
                    `}
                    title={`Month ${idx + 1} (${Math.floor(idx/12)} years old)`}
                  />
                ))}
              </div>

              <div className="mt-8 pt-8 border-t border-slate-100 flex flex-wrap justify-between gap-4 text-sm text-slate-400">
                <p>Birth: {format(new Date(birthDate), 'MMM d, yyyy')}</p>
                <p>Target: 100th Birthday ({format(addYears(new Date(birthDate), 100), 'yyyy')})</p>
              </div>
            </div>

            {/* Quote / Reflection */}
            <div className="text-center max-w-2xl mx-auto italic text-slate-500 py-4">
              "The days are long, but the years are short. Make every square count."
            </div>
          </div>
        )}
      </main>
    </div>
  );
};

interface StatCardProps {
  title: string;
  value: string | undefined;
  subtitle: string;
  icon: React.ReactNode;
  color: string;
}

const StatCard: React.FC<StatCardProps> = ({ title, value, subtitle, icon, color }) => (
  <div className="bg-white p-6 rounded-2xl shadow-sm border border-slate-100 hover:shadow-md transition-shadow">
    <div className="flex justify-between items-start mb-4">
      <div className={`p-2 rounded-lg ${color}`}>
        {icon}
      </div>
      <span className="text-xs font-bold text-slate-400 uppercase tracking-wider">{title}</span>
    </div>
    <div className="text-3xl font-black text-slate-800 mb-1">{value}</div>
    <div className="text-sm text-slate-500">{subtitle}</div>
  </div>
);

export default App;

